use Storable qw(nstore retrieve);

# Create a new session
sub createSession {
    my $session = {}; # Empty hashref for the session data
    $session->{"id"} = genId(); # Generate a unique ID for this session
    $session->{"data"} = {}; # Initialize the session data as an empty hashref
    nstore($session, "/tmp/sess_$session->{id}"); # Store the session data in a file with the session ID
    return $session;
}

# Load a session from its ID
sub loadSession {
    my $sessionId = shift; # Get the session ID from the arguments
    if (retrieve("/tmp/sess_$sessionId")) { # If the session file exists, load it and return the session data
        return retrieve("/tmp/sess_$sessionId");
    } else { # If the session file doesn't exist, create a new one
        return createSession();
    }
}

# Generate a unique ID for this session
sub genId {
    my $id = int(rand(100000)); # Generate a random 6-digit number
    while (retrieve("/tmp/sess_$id")) { # If the generated ID already exists, generate a new one and try again
        $id = int(rand(100000));
    }
    return $id;
}